import{_ as a,o as b,c as t,j as r,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"命定风暴","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/6.可升级/命定风暴.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/6.可升级/命定风暴.md"}'),d={name:"4.资源分区/7.物品与装备/2.武器/近战武器/6.可升级/命定风暴.md"};function o(p,e,l,_,i,c){return b(),t("div",null,[...e[0]||(e[0]=[r("h1",{id:"命定风暴",tabindex:"-1"},[n("命定风暴 "),r("a",{class:"header-anchor",href:"#命定风暴","aria-label":'Permalink to "命定风暴"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌031")])])],-1),s('<h1 id="命定风暴-1" tabindex="-1">命定风暴 <a class="header-anchor" href="#命定风暴-1" aria-label="Permalink to &quot;命定风暴&quot;">​</a></h1><p>命定风暴<br> 本质：魔幻本质<br> 占据鞋袜位<br> 武器-鞋<br> 命定风暴外表为一双发着微弱白光的白色羊毛袜。<br> 命定风暴为差价升级。</p><p>D+500<br> 命定风暴-祈愿微风<br> [微风伴随在你的左右]<br> 武器伤害：3L+1<br> 武器特性： 【肉搏武器】【风暴凝聚】【超速汽轮】<br> 伤害类型：物理-钝击<br> 体积：1<br> 风暴凝聚：气流将在袜子周围不断凝聚，为你的踢击加强威力，同时气流会带走灰尘，现在你不用再担心它脏掉了。<br> 在经历过一场进行过同级难度的战斗的影片结束后，该武器的攻击检定额外获得2dp的器械加值，至多生效4次。生效4次后，命定风暴外表上额外缠绕一层厚厚的气流。<br> 超速汽轮：回转的气流在脚上凝聚，踢击更快更强。<br> 你的攻击获得【长点射】特性，在外观上看是你的攻击十分的凌厉快速。</p><p>C+1000<br> 命定风暴-祈愿微风-轻灵阵风<br> [微风伴随在你的左右]<br> [阵风吹起向往的愿望]<br> 武器伤害：5L+2<br> 武器特性： 【肉搏武器】【风暴凝聚】【超速汽轮】【轰鸣之愿】<br> 伤害类型：物理-钝击 /能量-音波<br> 体积：1<br> 风暴凝聚：气流将在袜子周围不断凝聚，为你的踢击加强威力，同时气流会带走灰尘，现在你不用再担心它脏掉了。<br> 在经历过一场进行过同级难度的战斗的影片结束后，该武器的攻击检定额外获得2dp的器械加值，至多生效4次。生效4次后，命定风暴外表上额外缠绕一层厚厚的气流。<br> 超速汽轮：回转的气流在脚上凝聚，踢击更快更强。<br> 你的攻击获得【长点射】特性，在外观上看是你的攻击十分的凌厉快速。<br> 轰鸣之愿：缠绕的气流带起冲击性的轰鸣，摧毁前往目标前的一切障碍<br> 该武器现在具有【能量武器】特性，可造成音波伤害，命定风暴外表上的白光更加明亮。</p><p>B+2000<br> 命定风暴-祈愿微风-轻灵阵风-怒号狂风<br> [微风伴随在你的左右]<br> [阵风吹起向往的愿望]<br> [狂风扫清前方的阻碍]<br> 武器伤害：6L+4<br> 武器特性： 【肉搏武器】【接触攻击】【风暴凝聚】【超速汽轮】【轰鸣之愿】【风雨化躯】<br> 伤害类型：物理-钝击 /能量-音波<br> 体积：1<br> 风暴凝聚：气流将在袜子周围不断凝聚，为你的踢击加强威力，同时气流会带走灰尘，现在你不用再担心它脏掉了。<br> 在经历过一场进行过同级难度的战斗的影片结束后，该武器的攻击检定额外获得2dp的器械加值，至多生效4次。生效4次后，命定风暴外表上额外缠绕一层厚厚的气流。<br> 超速汽轮：回转的气流在脚上凝聚，踢击更快更强。<br> 你的攻击获得【长点射】特性，在外观上看是你的攻击十分的凌厉快速。<br> 轰鸣之愿：缠绕的气流带起冲击性的轰鸣，摧毁前往目标前的一切障碍<br> 该武器现在具有【能量武器】特性，造成音波伤害，命定风暴外表上的白光更加明亮。<br> 风雨化躯：我祈求狂风，我操控狂风，我即是迫近的狂风<br> 每场战斗一次，以一个整轮动作进行一次类全防御行为，命定风暴的气流将变得狂乱并扩大缠绕在你的双腿上，那之后，在本场战斗中，每轮你第一次使用该武器发动的攻击造成的伤害增加一倍。<br> 作为代价，你身体的生命力被命运的力量扯出了体外，在获得上述效果的时候你将获得5点不可豁免的命运来源的流血点数。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',7)])])}const m=a(d,[["render",o]]);export{f as __pageData,m as default};
